    {
      name: 'refundedBy',
      type: 'relationship',
      relationTo: 'users',
      admin: {
        description: 'Admin who processed the refund',
        readOnly: true,
      },
    },
    {
      name: 'refundedAt',
      type: 'date',
      admin: {
        description: 'When the refund was processed',
        readOnly: true,
>>>>>>> origin/dev
      },
    },

    createdByField,
  ],
  timestamps: true,
}

